{{CSS|content=@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Poiret+One&display=swap');

:root {
  --tv-black: 28, 28, 28;
  --tv-screen: 230, 230, 230;
  --tv-blue: 190, 190, 190;
  --tv-white: 248, 248, 248;
  --tv-pink: 210, 210, 210;
  --tv-shadow: 0, 0, 0;

  --body-font: 'Playfair Display', serif;
  --retro-font: 'Poiret One', cursive;
}

.page-container .page {
  border: 3px solid rgb(var(--tv-blue));
  margin: 12px auto;
  border-radius: 8px;
  box-shadow: 0 0 18px rgba(var(--tv-screen), 0.25), inset 0 0 9px rgba(var(--tv-blue), 0.18);
  background: linear-gradient(
    135deg,
    rgb(var(--tv-black)),
    rgba(var(--tv-blue), 0.07),
    rgba(var(--tv-screen), 0.04)
  );
  background-image:
    repeating-linear-gradient(0deg, rgba(var(--tv-white), 0.025) 0px, transparent 2px, transparent 4px);
}

.theme-fandomdesktop-dark {
  --theme-page-background-color: rgb(var(--tv-black));
  --theme-page-background-color--secondary: rgba(var(--tv-blue), 0.07);
  --theme-link-color: rgb(248, 248, 248);
  --theme-border-color: rgb(var(--tv-pink));
  --theme-community-header-color: rgb(var(--tv-blue));
  --theme-sticky-nav-background-color: rgba(var(--tv-black), 0.97);
  --theme-sticky-nav-text-color: rgb(var(--tv-screen));
  --theme-sticky-nav-text-color--hover: rgb(var(--tv-pink));
}

.theme-fandomdesktop-light {
  --theme-page-background-color: rgba(var(--tv-white), 0.96);
  --theme-page-background-color--secondary: rgb(var(--tv-black));
  --theme-link-color: rgb(40, 40, 40);
  --theme-border-color: rgb(var(--tv-pink));
  --theme-community-header-color: rgb(var(--tv-screen));
  --theme-sticky-nav-background-color: rgba(var(--tv-white), 0.98);
  --theme-sticky-nav-text-color: rgb(var(--tv-black));
  --theme-sticky-nav-text-color--hover: rgb(var(--tv-blue));
}

a,
a:visited {
  color: rgb(248, 248, 248) !important;
  text-decoration: none;
  transition: color 0.3s ease, text-shadow 0.3s ease;
}
a:hover,
a:focus {
  color: rgb(var(--tv-screen)) !important;
  text-shadow: 0 0 5px rgba(var(--tv-screen), 0.65),
               0 0 10px rgba(var(--tv-blue), 0.45);
}

.page-side-tools .page-side-tool {
  border: 2px solid rgb(var(--tv-screen));
  box-shadow: 0 0 9px rgba(var(--tv-screen), 0.35);
  border-radius: 50%;
  background-color: rgba(var(--tv-black), 0.94);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.page-side-tool:hover {
  transform: scale(1.07);
  box-shadow: 0 0 16px rgba(var(--tv-blue), 0.65);
}

.titleblock, .dark-titleblock {
  background: radial-gradient(circle at top, rgba(var(--tv-screen), 0.12), rgba(var(--tv-black), 0.97));
  border: 3px solid rgb(var(--tv-pink));
  border-radius: 8px;
  padding: 1.1rem;
  font-family: var(--retro-font);
  font-weight: 400;
  color: rgb(var(--tv-screen));
  text-shadow: 0 0 5px rgba(var(--tv-screen), 0.65), 0 0 11px rgba(var(--tv-blue), 0.45);
  font-size: 2.4em;
  letter-spacing: 4px;
  transform: rotate(-0.4deg);
  animation: subtle-glow 5s infinite alternate;
}

.progress {
  background: rgba(var(--tv-black), 0.97);
  border: 2px solid rgb(var(--tv-blue));
  border-radius: 8px;
  color: rgb(var(--tv-white));
  box-shadow: 0 0 9px rgba(var(--tv-screen), 0.35);
}
.progress .bar {
  background: linear-gradient(to right, rgb(var(--tv-blue)), rgb(var(--tv-screen)));
  border-radius: 6px;
  box-shadow: 0 0 13px rgba(var(--tv-screen), 0.55);
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--retro-font);
  color: rgb(var(--tv-screen));
  text-transform: uppercase;
  letter-spacing: 6px;
  text-shadow: 0 0 6px rgba(var(--tv-screen), 0.65), 0 0 13px rgba(var(--tv-blue), 0.5);
  font-size: calc(1.5rem + 0.7vw);
}
h1 {
  font-size: calc(2.2rem + 1.1vw);
}

@keyframes subtle-glow {
  0%, 100% {
    opacity: 1;
    text-shadow: 0 0 6px rgba(var(--tv-screen), 0.75), 0 0 14px rgba(var(--tv-blue), 0.55);
  }
  50% {
    opacity: 0.94;
    text-shadow: 0 0 4px rgba(var(--tv-screen), 0.5), 0 0 9px rgba(var(--tv-blue), 0.35);
  }
}
}}

